def is_balanced(s: str) -> bool:
    """
    Returns True iff every opening bracket in s has a matching closing bracket
    of the same type AND the nesting order is valid.
    Bracket pairs are (), [], and {}. Any other characters are ignored.
    An empty string is balanced.
    """
    stack = []
    opening = {'(', '[', '{'}
    closing = {')', ']', '}'}
    matching = {')': '(', ']': '[', '}': '{'}

    for char in s:
        if char in opening:
            stack.append(char)
        elif char in closing:
            if not stack:
                return False
            if stack[-1] != matching[char]:
                return False
            stack.pop()

    return len(stack) == 0
